code = """import pandas as pd
import json
import re

business_data_raw_string = locals()['var_function-call-5652457132629444987']['results'][0]

# Extract the JSON array string from the raw output using regex
json_match = re.search(r'\[.*\]', business_data_raw_string, re.DOTALL)
if json_match:
    cleaned_business_data_str = json_match.group(0)
else:
    cleaned_business_data_str = '[]' # Fallback to empty list JSON if no JSON array found

business_data = json.loads(cleaned_business_data_str)
df_business = pd.DataFrame(business_data)

# If df_business is empty, handle this case
if df_business.empty:
    print('__RESULT__:')
    print(json.dumps({'highest_review_state_name': None, 'business_refs_in_highest_state': []}))
else:
    def extract_state(description):
        # Regex to find a 2-letter state code, optionally followed by a 5-digit zip code
        # Pattern: , ST 12345 or , ST
        match = re.search(r',\s*([A-Z]{2})(?:\s+\d{5})?\b', description)
        if match:
            return match.group(1)
        return None

    df_business['state'] = df_business['description'].apply(extract_state)
    df_business['review_count'] = pd.to_numeric(df_business['review_count'], errors='coerce')

    # Filter out rows where state is None before grouping
    df_business_filtered = df_business.dropna(subset=['state'])

    if df_business_filtered.empty:
        print('__RESULT__:')
        print(json.dumps({'highest_review_state_name': None, 'business_refs_in_highest_state': []}))
    else:
        state_review_counts = df_business_filtered.groupby('state')['review_count'].sum().reset_index()

        if state_review_counts.empty:
            print('__RESULT__:')
            print(json.dumps({'highest_review_state_name': None, 'business_refs_in_highest_state': []}))
        else:
            highest_review_state_info = state_review_counts.loc[state_review_counts['review_count'].idxmax()]
            highest_review_state_name = highest_review_state_info['state']

            business_ids_in_highest_state = df_business_filtered[df_business_filtered['state'] == highest_review_state_name]['business_id'].tolist()
            business_refs_in_highest_state = [bid.replace('businessid_', 'businessref_') for bid in business_ids_in_highest_state]

            print('__RESULT__:')
            print(json.dumps({'highest_review_state_name': highest_review_state_name, 'business_refs_in_highest_state': business_refs_in_highest_state}))"""

